{
  "domain_analysis": {
    "business_context": "A logistics platform managing the lifecycle of parcel shipments from creation through transit to delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A parcel moving from a pickup address to a delivery address, progressing through defined lifecycle states." },
      { "term": "Pickup Address", "definition": "The origin location where a parcel is collected." },
      { "term": "Delivery Address", "definition": "The destination location where a parcel is to be delivered." },
      { "term": "Shipment State", "definition": "The lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered." },
      { "term": "Weight Bracket", "definition": "A pricing tier determined by parcel weight: Standard (0–10 kg), Heavy (10–50 kg), Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for parcels weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for parcels weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for parcels weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — it cannot be routed, picked up, or delivered. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a missing or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions follow the directed graph: Pending → In Transit → Delivered. No reverse transitions are permitted.",
      "invariant": true,
      "invariant_justification": "State integrity constraint. Reversing physical logistics states (e.g., un-delivering a parcel) would corrupt tracking data, billing records, and downstream processes. The state machine is monotonically forward.",
      "testable_assertion": "A shipment in 'In Transit' state cannot transition to 'Pending'. A shipment in 'Delivered' state cannot transition to any other state."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state — no further state changes are allowed.",
      "invariant": true,
      "invariant_justification": "Once a parcel is delivered, the business obligation is fulfilled. Altering this state would break audit trails, proof-of-delivery records, and billing finality.",
      "testable_assertion": "Any state change attempted on a Delivered shipment must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "A parcel with zero or negative weight is physically impossible. The 1000 kg upper bound reflects a physical/operational constraint — vehicles, handling equipment, and insurance have hard limits.",
      "testable_assertion": "A shipment with weight ≤ 0 or weight > 1000 must be rejected at creation."
    },
    {
      "id": "BR-5",
      "rule": "Weight brackets determine pricing tier: Standard (0 < weight ≤ 10 kg), Heavy (10 < weight ≤ 50 kg), Freight (50 < weight ≤ 1000 kg).",
      "invariant": false,
      "invariant_justification": "The bracket thresholds and tier names are business policy — management could adjust the boundaries (e.g., move Heavy to 15 kg) without corrupting system state.",
      "testable_assertion": "A 10 kg parcel is classified as Standard. A 10.01 kg parcel is classified as Heavy. A 50.01 kg parcel is classified as Freight."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A request to create a shipment with a valid pickup address, delivery address, and weight of 5 kg",
      "when": "The shipment is created",
      "then": "The shipment is persisted in Pending state with weight bracket Standard"
    },
    {
      "id": "AC-2",
      "given": "A request to create a shipment with a missing pickup address",
      "when": "Creation is attempted",
      "then": "The system rejects the request and no shipment is created"
    },
    {
      "id": "AC-3",
      "given": "A request to create a shipment with a missing delivery address",
      "when": "Creation is attempted",
      "then": "The system rejects the request and no shipment is created"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "It is transitioned to In Transit",
      "then": "The state changes to In Transit successfully"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "A transition to Pending is attempted",
      "then": "The transition is rejected and the shipment remains In Transit"
    },
    {
      "id": "AC-6",
      "given": "A shipment in In Transit state",
      "when": "It is transitioned to Delivered",
      "then": "The state changes to Delivered successfully"
    },
    {
      "id": "AC-7",
      "given": "A shipment in Delivered state",
      "when": "Any state transition is attempted",
      "then": "The transition is rejected and the shipment remains Delivered"
    },
    {
      "id": "AC-8",
      "given": "A request to create a shipment with weight 0 kg",
      "when": "Creation is attempted",
      "then": "The system rejects the request"
    },
    {
      "id": "AC-9",
      "given": "A request to create a shipment with weight -5 kg",
      "when": "Creation is attempted",
      "then": "The system rejects the request"
    },
    {
      "id": "AC-10",
      "given": "A request to create a shipment with weight 1001 kg",
      "when": "Creation is attempted",
      "then": "The system rejects the request"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight exactly 10 kg",
      "when": "The weight bracket is determined",
      "then": "It is classified as Standard"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight 10.01 kg",
      "when": "The weight bracket is determined",
      "then": "It is classified as Heavy"
    },
    {
      "id": "AC-13",
      "given": "A shipment with weight exactly 50 kg",
      "when": "The weight bracket is determined",
      "then": "It is classified as Heavy"
    },
    {
      "id": "AC-14",
      "given": "A shipment with weight 50.01 kg",
      "when": "The weight bracket is determined",
      "then": "It is classified as Freight"
    },
    {
      "id": "AC-15",
      "given": "A shipment with weight exactly 1000 kg",
      "when": "The weight bracket is determined",
      "then": "It is classified as Freight and creation succeeds"
    }
  ],

  "edge_cases": [
    { "scenario": "Shipment created with weight exactly at a bracket boundary (10 kg, 50 kg)", "expected_behavior": "The boundary value belongs to the lower bracket (10 kg = Standard, 50 kg = Heavy). Spec says '0-10 is standard, 10-50 is heavy' — the inclusive boundary is on the lower tier." },
    { "scenario": "Attempt to transition directly from Pending to Delivered, skipping In Transit", "expected_behavior": "Spec does not explicitly address this. The stated transitions are Pending → In Transit → Delivered. Skipping In Transit should be rejected unless the business explicitly permits it." },
    { "scenario": "Shipment created with weight exactly 1000 kg", "expected_behavior": "Should succeed — 1000 kg is the upper limit, classified as Freight." },
    { "scenario": "Pickup and delivery addresses are identical", "expected_behavior": "Spec does not prohibit this. Likely a data quality concern but not a domain invariant — some businesses allow same-address shipments (e.g., internal warehouse transfers)." },
    { "scenario": "Weight is provided with extreme decimal precision (e.g., 10.0000001 kg)", "expected_behavior": "Should be classified as Heavy. Implementation must handle floating-point comparison correctly at bracket boundaries." },
    { "scenario": "Attempt to modify shipment weight after creation", "expected_behavior": "Spec is silent on mutability of weight post-creation. If weight changes, the bracket could change, affecting pricing. Recommend treating weight as immutable after creation." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives pricing. Incorrect boundary logic (off-by-one at 10 kg or 50 kg) could systematically under- or over-charge customers, causing revenue leakage or customer disputes at scale.",
    "operational": "State machine integrity ensures reliable shipment tracking. If reverse transitions were allowed, warehouse operations, driver dispatching, and inventory counts become unreliable.",
    "user": "Customers depend on accurate shipment states for tracking visibility. Delivered finality gives customers confidence in proof-of-delivery. Clear weight validation prevents confusion from rejected shipments.",
    "risk": "Primary risks are (1) bracket boundary bugs causing systematic pricing errors, (2) state machine violations causing phantom or zombie shipments in tracking systems, and (3) missing validation allowing corrupt data (zero-weight, addressless shipments) into the system.",
    "stakeholders_affected": [
      { "group": "Customers (senders)", "impact": "Directly affected by pricing accuracy and shipment state visibility. Incorrect brackets mean wrong charges." },
      { "group": "Recipients", "impact": "Depend on accurate Delivered state for proof-of-delivery and planning." },
      { "group": "Operations / Warehouse", "impact": "State machine correctness drives dispatch, routing, and inventory management." },
      { "group": "Finance / Billing", "impact": "Weight brackets feed directly into invoicing. Boundary errors compound across thousands of shipments." },
      { "group": "Customer Support", "impact": "State anomalies (e.g., delivered shipments changing state) generate support tickets and erode trust." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear on core rules (state machine, weight validation, brackets) but leaves several domain questions unanswered: whether Pending→Delivered skip is allowed, whether weight is mutable after creation, what constitutes a valid address, and how bracket boundaries are defined at exact thresholds (the phrasing '0-10 kg is standard, 10-50 kg is heavy' creates ambiguity at exactly 10 kg and 50 kg). These gaps are manageable but require clarification before implementation.",
    "high_confidence_areas": [
      "State machine directionality (no reverse from In Transit, Delivered is terminal)",
      "Weight must be positive and ≤ 1000 kg",
      "Both addresses required at creation",
      "Three weight brackets exist with the stated ranges"
    ],
    "low_confidence_areas": [
      "Exact bracket boundary ownership (is 10 kg Standard or Heavy? Spec says '0-10' and '10-50' — 10 appears in both ranges)",
      "Whether Pending → Delivered direct transition is permitted or must go through In Transit",
      "Whether weight or addresses are mutable after shipment creation",
      "What constitutes a 'valid' address (format, geocoding, existence)"
    ],
    "assumptions": [
      "Bracket boundaries are inclusive on the lower end: 10 kg = Standard, 50 kg = Heavy (interpreting '0-10' as 0 < w ≤ 10)",
      "Initial state of a newly created shipment is Pending",
      "Shipment state transitions are the only valid ones in the directed graph Pending → In Transit → Delivered (no skipping)",
      "Weight is set at creation and immutable thereafter"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The bracket boundary at 10 kg is ambiguous: '0-10 kg is standard' and '10-50 kg is heavy' both include 10 kg. Which bracket owns the boundary value?",
      "affected_stakeholders": ["Finance / Billing", "Customers (senders)"],
      "options": ["10 kg belongs to Standard (upper-inclusive: 0 < w ≤ 10)", "10 kg belongs to Heavy (lower-inclusive: 10 ≤ w < 50)"],
      "recommendation": "Adopt upper-inclusive convention (10 kg = Standard, 50 kg = Heavy). This is the more common convention in logistics pricing and is more customer-friendly for boundary weights."
    },
    {
      "type": "ambiguity",
      "description": "Can a shipment transition directly from Pending to Delivered (skipping In Transit)? The spec only states In Transit cannot go back to Pending and Delivered is terminal, but does not explicitly define the full set of allowed transitions.",
      "affected_stakeholders": ["Operations / Warehouse", "Customers (senders)", "Recipients"],
      "options": ["Allow only Pending → In Transit → Delivered (strict sequential)", "Allow Pending → Delivered as well (for edge cases like cancelled-before-pickup re-routed to delivered)"],
      "recommendation": "Enforce strict sequential transitions (Pending → In Transit → Delivered). Skipping states breaks operational tracking and audit trails."
    },
    {
      "type": "missing_context",
      "description": "The spec does not define what constitutes a valid address. Is a simple non-empty string sufficient, or must addresses conform to a structure (street, city, postal code, country)? Is geocoding or address verification required?",
      "affected_stakeholders": ["Operations / Warehouse", "Customers (senders)", "Recipients"],
      "options": ["Non-empty string validation only", "Structured address with required fields", "Full address verification with geocoding"],
      "recommendation": "At minimum require structured addresses (street, city, postal code, country) to enable routing. Defer geocoding to a later phase."
    }
  ],

  "rejection_reasons": []
}

